Code.Terraform:
```hcl
resource "aws_iam_role" "bedrock_agent" {
  name                 = "<execution_role_name>"
  assume_role_policy   = data.aws_iam_policy_document.trust.json
  permissions_boundary = aws_iam_policy.bedrock_agent_boundary.arn  # CRITICAL: caps maximum privileges
}

resource "aws_iam_role_policy" "bedrock_agent_inline" {
  role   = aws_iam_role.bedrock_agent.name
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [{
      Effect   = "Allow",
      Action   = ["s3:GetObject"],            # CRITICAL: narrow action
      Resource = ["arn:aws:s3:::my-rag-bucket/*"]  # CRITICAL: narrow resource
    }]
  })
}
```
